import{_ as e,o as s,c as a,ae as n}from"./chunks/framework.L6C4hHZp.js";const m=JSON.parse('{"title":"Layered Memory System","description":"","frontmatter":{},"headers":[],"relativePath":"memory-system.md","filePath":"memory-system.md"}'),o={name:"memory-system.md"};function r(l,t,i,d,p,c){return s(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="layered-memory-system" tabindex="-1">Layered Memory System <a class="header-anchor" href="#layered-memory-system" aria-label="Permalink to &quot;Layered Memory System&quot;">​</a></h1><blockquote><p>GenericAgent&#39;s memory crystallizes throughout task execution, enabling the agent to build stable, efficient working patterns over time.</p></blockquote><h2 id="_1-memory-architecture" tabindex="-1">1. Memory Architecture <a class="header-anchor" href="#_1-memory-architecture" aria-label="Permalink to &quot;1. Memory Architecture&quot;">​</a></h2><p>GenericAgent uses a <strong>5-layer memory system</strong> (L0-L4) that progressively crystallizes experience from raw context into reusable skills:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                         Context                              │</span></span>
<span class="line"><span>│              (Current conversation + state)                  │</span></span>
<span class="line"><span>└──────────────────────────┬───────────────────────────────────┘</span></span>
<span class="line"><span>                           │</span></span>
<span class="line"><span>            ┌──────────────┴──────────────┐</span></span>
<span class="line"><span>            ▼                             ▼</span></span>
<span class="line"><span>┌───────────────────────┐     ┌───────────────────────┐</span></span>
<span class="line"><span>│   Working Memory      │     │    Long-term Memory   │</span></span>
<span class="line"><span>│   (In-context)        │     │    (Persistent)       │</span></span>
<span class="line"><span>└───────────────────────┘     └───────────────────────┘</span></span>
<span class="line"><span>                                    │</span></span>
<span class="line"><span>         ┌──────────┬──────────┬─────┴─────┬──────────┐</span></span>
<span class="line"><span>         ▼          ▼          ▼           ▼          ▼</span></span>
<span class="line"><span>       L0 Meta    L1 Insight  L2 Global   L3 Skills  L4 Sessions</span></span></code></pre></div><h2 id="_2-layer-specifications" tabindex="-1">2. Layer Specifications <a class="header-anchor" href="#_2-layer-specifications" aria-label="Permalink to &quot;2. Layer Specifications&quot;">​</a></h2><h3 id="l0-—-meta-rules" tabindex="-1">L0 — Meta Rules <a class="header-anchor" href="#l0-—-meta-rules" aria-label="Permalink to &quot;L0 — Meta Rules&quot;">​</a></h3><p><strong>Purpose</strong>: Core behavioral rules and system constraints.</p><table tabindex="0"><thead><tr><th>Attribute</th><th>Value</th></tr></thead><tbody><tr><td>Persistence</td><td>Always in context</td></tr><tr><td>Update Frequency</td><td>Rarely (system-level)</td></tr><tr><td>Content Type</td><td>Hard constraints, red lines</td></tr></tbody></table><p><strong>Example content</strong>:</p><ul><li>&quot;禁止下场干活：只读、只判断、只干预&quot;</li><li>&quot;每项必须有独立完成判据&quot;</li><li>&quot;禁止凭记忆执行&quot;</li></ul><hr><h3 id="l1-—-insight-index" tabindex="-1">L1 — Insight Index <a class="header-anchor" href="#l1-—-insight-index" aria-label="Permalink to &quot;L1 — Insight Index&quot;">​</a></h3><p><strong>Purpose</strong>: Minimal memory index for fast routing and recall.</p><table tabindex="0"><thead><tr><th>Attribute</th><th>Value</th></tr></thead><tbody><tr><td>Persistence</td><td>Long-term</td></tr><tr><td>Update Frequency</td><td>On new skill creation</td></tr><tr><td>Content Type</td><td>Index/routing pointers</td></tr></tbody></table><p>L1 acts as a &quot;table of contents&quot; for L3 Skills. When a new task arrives, L1 helps route to relevant skills without loading full content.</p><hr><h3 id="l2-—-global-facts" tabindex="-1">L2 — Global Facts <a class="header-anchor" href="#l2-—-global-facts" aria-label="Permalink to &quot;L2 — Global Facts&quot;">​</a></h3><p><strong>Purpose</strong>: Stable knowledge accumulated over long-term operation.</p><table tabindex="0"><thead><tr><th>Attribute</th><th>Value</th></tr></thead><tbody><tr><td>Persistence</td><td>Permanent</td></tr><tr><td>Update Frequency</td><td>Infrequently</td></tr><tr><td>Content Type</td><td>User preferences, environment facts</td></tr></tbody></table><p><strong>Example content</strong>:</p><ul><li>User&#39;s name, timezone, coding style</li><li>Environment configuration</li><li>Stable API endpoints</li></ul><hr><h3 id="l3-—-task-skills-sops" tabindex="-1">L3 — Task Skills / SOPs <a class="header-anchor" href="#l3-—-task-skills-sops" aria-label="Permalink to &quot;L3 — Task Skills / SOPs&quot;">​</a></h3><p><strong>Purpose</strong>: Reusable workflows for completing specific task types.</p><table tabindex="0"><thead><tr><th>Attribute</th><th>Value</th></tr></thead><tbody><tr><td>Persistence</td><td>Permanent</td></tr><tr><td>Update Frequency</td><td>On task completion</td></tr><tr><td>Content Type</td><td>Standard Operating Procedures</td></tr></tbody></table><p>This is where <strong>self-evolution happens</strong>. Each completed task can be crystallized into an SOP for direct reuse.</p><p><strong>Key SOPs</strong>:</p><table tabindex="0"><thead><tr><th>SOP</th><th>Purpose</th></tr></thead><tbody><tr><td><code>plan_sop.md</code></td><td>Multi-step planning with verification</td></tr><tr><td><code>supervisor_sop.md</code></td><td>Oversight/monitoring mode</td></tr><tr><td><code>autonomous_operation_sop.md</code></td><td>Self-directed task execution</td></tr><tr><td><code>goal_mode_sop.md</code></td><td>Goal-driven reflection</td></tr><tr><td><code>vision_sop.md</code></td><td>Visual perception capability</td></tr></tbody></table><hr><h3 id="l4-—-session-archive" tabindex="-1">L4 — Session Archive <a class="header-anchor" href="#l4-—-session-archive" aria-label="Permalink to &quot;L4 — Session Archive&quot;">​</a></h3><p><strong>Purpose</strong>: Archived task records distilled from finished sessions for long-horizon recall.</p><table tabindex="0"><thead><tr><th>Attribute</th><th>Value</th></tr></thead><tbody><tr><td>Persistence</td><td>Long-term</td></tr><tr><td>Update Frequency</td><td>On session end</td></tr><tr><td>Content Type</td><td>Compressed session logs</td></tr></tbody></table><p>L4 stores distilled session records that can be referenced for similar future tasks.</p><h2 id="_3-memory-flow" tabindex="-1">3. Memory Flow <a class="header-anchor" href="#_3-memory-flow" aria-label="Permalink to &quot;3. Memory Flow&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Task Execution:</span></span>
<span class="line"><span>1. Task arrives → L1 Insight Index routes to relevant L3 Skills</span></span>
<span class="line"><span>2. If no skill matches → Autonomous exploration mode</span></span>
<span class="line"><span>3. During execution → L0 Meta Rules constrain behavior</span></span>
<span class="line"><span>4. On completion → Results write to L2 Global Facts (if stable knowledge)</span></span>
<span class="line"><span>5. On task crystallization → New skill saves to L3 Skills</span></span>
<span class="line"><span>6. Session end → Session distillate saves to L4 Sessions</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Skill Invocation:</span></span>
<span class="line"><span>1. New task arrives</span></span>
<span class="line"><span>2. L1 checks for matching L3 Skill</span></span>
<span class="line"><span>3. If found → Direct skill recall and execution</span></span>
<span class="line"><span>4. If not found → Autonomous exploration → New skill creation</span></span></code></pre></div><h2 id="_4-memory-tools" tabindex="-1">4. Memory Tools <a class="header-anchor" href="#_4-memory-tools" aria-label="Permalink to &quot;4. Memory Tools&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tool</th><th>Function</th></tr></thead><tbody><tr><td><code>update_working_checkpoint</code></td><td>Save current context to working checkpoint</td></tr><tr><td><code>start_long_term_update</code></td><td>Trigger long-term memory update (skill crystallization)</td></tr></tbody></table><h2 id="_5-self-evolution-via-memory" tabindex="-1">5. Self-Evolution via Memory <a class="header-anchor" href="#_5-self-evolution-via-memory" aria-label="Permalink to &quot;5. Self-Evolution via Memory&quot;">​</a></h2><p>The key to GenericAgent&#39;s self-evolution is the <strong>crystallization loop</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[New Task] </span></span>
<span class="line"><span>    ↓ (no matching skill in L1)</span></span>
<span class="line"><span>[Autonomous Exploration]</span></span>
<span class="line"><span>    ↓ (install deps, write scripts, debug)</span></span>
<span class="line"><span>[Task Completion]</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>[Crystallize Execution Path]</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>[Write to L3 Skills via start_long_term_update]</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>[Update L1 Insight Index]</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>[Next similar task → Direct recall from L3]</span></span></code></pre></div><p>This means: <strong>The longer you use GenericAgent, the more capable it becomes, forming a skill tree unique to you.</strong></p><h2 id="_6-memory-persistence" tabindex="-1">6. Memory Persistence <a class="header-anchor" href="#_6-memory-persistence" aria-label="Permalink to &quot;6. Memory Persistence&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Storage Location</th><th>Format</th></tr></thead><tbody><tr><td>L0</td><td>In-context</td><td>N/A</td></tr><tr><td>L1</td><td><code>memory/</code></td><td>Markdown index files</td></tr><tr><td>L2</td><td><code>memory/</code></td><td>Markdown fact files</td></tr><tr><td>L3</td><td><code>memory/</code></td><td>Markdown SOP files</td></tr><tr><td>L4</td><td><code>memory/L4_raw_sessions/</code></td><td>Compressed session files</td></tr></tbody></table><p>All memory is stored as <strong>plain text Markdown files</strong> — easily readable, editable, and portable.</p>`,45)])])}const u=e(o,[["render",r]]);export{m as __pageData,u as default};
